import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Edit, Trash2, Image as ImageIcon } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminArtworks = () => {
  const [artworks, setArtworks] = useState<any[]>([]);

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtworks();
      // Logic: Ensure it's an array, otherwise map() fails
      setArtworks(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("Gallery Sync Failed");
      setArtworks([]);
    }
  };

  useEffect(() => { fetchData(); }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Gallery <span className="text-primary">Artworks</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Visual Assets</p>
        </div>
        <Link to="/admin/artworks/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-all shadow-xl">
          <Plus size={16} /> Catalog Artwork
        </Link>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {artworks.map((art: any) => (
          <div key={art._id} className="bg-white dark:bg-[#0f0f0f] rounded-[2rem] overflow-hidden border border-gray-100 dark:border-white/5 group shadow-sm">
             <div className="h-48 bg-gray-100 dark:bg-white/5 flex items-center justify-center overflow-hidden">
               {art.Cloudinary_Image1 ? (
                 <img src={art.Cloudinary_Image1} className="w-full h-full object-cover transition-transform group-hover:scale-105" alt={art.Title_En} />
               ) : (
                 <ImageIcon size={32} className="text-gray-300" />
               )}
             </div>
             <div className="p-6">
               <h4 className="font-black uppercase text-xs italic truncate mb-1">{art.Title_En || 'Untitled Piece'}</h4>
               <p className="text-[10px] font-bold text-primary mb-4">{art.Artist_ID || 'Unknown Artist'}</p>
               <div className="flex gap-2">
                 <Link to={`/admin/artworks/edit/${art.Artwork_ID}`} className="flex-1 py-3 bg-gray-50 dark:bg-white/5 rounded-xl font-black text-[9px] uppercase text-center hover:bg-black hover:text-white transition-all">Modify</Link>
                 <button className="px-4 py-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all"><Trash2 size={14}/></button>
               </div>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};
